import{_ as s,o as a,c as i,ag as t}from"./chunks/framework.Bo7atV7P.js";const g=JSON.parse('{"title":"Codemods","description":"","frontmatter":{},"headers":[],"relativePath":"upgrading/codemods.md","filePath":"upgrading/codemods.md","lastUpdated":1782193515000}'),n={name:"upgrading/codemods.md"};function o(r,e,d,h,l,p){return a(),i("div",null,[...e[0]||(e[0]=[t(`<h1 id="codemods" tabindex="-1">Codemods <a class="header-anchor" href="#codemods" aria-label="Permalink to &quot;Codemods&quot;">​</a></h1><p>When a <code>webentor-core</code> release requires a mechanical change to <strong>consumer-owned theme code</strong> (PHP / TS / CSS / JSON), the fix ships as a versioned <strong>codemod</strong> in the <a href="https://www.npmjs.com/package/@webikon/webentor-codemods" target="_blank" rel="noreferrer"><code>@webikon/webentor-codemods</code></a> package. You run it with one command — no install — so the change that core&#39;s update <em>requires</em> comes with the tool that <em>performs</em> it.</p><p>This is separate from syncing the setup runtime (<code>scripts/setup-core</code> via <code>git subtree pull</code>, see <a href="./starter-upgrades.html">Starter Upgrades</a>). Codemods handle <strong>code transforms</strong> driven by package updates, and run independently of whether <code>webentor-setup</code> is present in your project.</p><p>The engine is <a href="https://ast-grep.github.io" target="_blank" rel="noreferrer">ast-grep</a>: rules match the <strong>AST</strong>, so they tolerate formatting differences a regex would miss, and only touch the targeted structure.</p><h2 id="running-a-codemod" tabindex="-1">Running a codemod <a class="header-anchor" href="#running-a-codemod" aria-label="Permalink to &quot;Running a codemod&quot;">​</a></h2><p>From your <strong>project root</strong> (the directory containing <code>web/app/themes/…</code>):</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># List what&#39;s available</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dlx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @webikon/webentor-codemods</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Preview a migration — dry-run, prints a diff, writes nothing</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dlx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @webikon/webentor-codemods</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">i</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Apply it</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dlx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @webikon/webentor-codemods</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">i</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --apply</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Or run every migration for a core version range at once</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dlx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @webikon/webentor-codemods</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --since</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0.13.0</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --to</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0.15.0</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --apply</span></span></code></pre></div><p>Migration ids encode their package + target version: <strong>webentor-core</strong> migrations use the bare core version (<code>0.13.0</code>, <code>0.15.0</code>); other packages use a <code>&lt;package&gt;-&lt;version&gt;</code> prefix (e.g. <code>starter-2.1.1</code> for a starter-only release).</p><p>Options:</p><ul><li><code>--path &lt;dir&gt;</code> — target a different directory (defaults to the current one).</li><li><code>--package &lt;name&gt;</code> — narrow <code>--since</code> to a package (defaults to <code>webentor-core</code>).</li><li><code>npx</code> works in place of <code>pnpm dlx</code> if you prefer.</li></ul><p><strong>Recommended flow:</strong> always dry-run first, review the diff, then <code>--apply</code>. After applying, rebuild the theme and clear caches:</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --dir</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> web/app/themes/</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">them</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">wp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> acorn</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> optimize:clear</span></span></code></pre></div><h2 id="safety-guarantees" tabindex="-1">Safety guarantees <a class="header-anchor" href="#safety-guarantees" aria-label="Permalink to &quot;Safety guarantees&quot;">​</a></h2><ul><li><strong>Idempotent</strong> — re-running an already-applied migration is a no-op.</li><li><strong>Conservative</strong> — anything that doesn&#39;t match the exact targeted shape (a heavily customized hook, say) is left untouched and reported, so you can migrate it by hand.</li><li><strong>Additive</strong> — the changelog sync (below) inserts entries above existing ones; it never clobbers your own changelog content.</li></ul><h2 id="changelog-sync" tabindex="-1">Changelog sync <a class="header-anchor" href="#changelog-sync" aria-label="Permalink to &quot;Changelog sync&quot;">​</a></h2><p>Besides code transforms, a migration keeps your project&#39;s changelogs up to date with the stack: it prepends the release&#39;s version block to the project root <code>changelog.md</code> and the theme <code>web/app/themes/*/changelog.md</code> (under the <code># … Changelog</code> H1). Already-present versions are skipped, so a range run (<code>run --since …</code>) backfills the full history in order.</p><h2 id="available-migrations" tabindex="-1">Available migrations <a class="header-anchor" href="#available-migrations" aria-label="Permalink to &quot;Available migrations&quot;">​</a></h2><table tabindex="0"><thead><tr><th>id</th><th>scope</th><th>what it does</th></tr></thead><tbody><tr><td><code>0.13.0</code></td><td>core 0.12 → 0.13</td><td>Moves the theme&#39;s <code>editor.css</code> + <code>button.style.css</code> enqueues from <code>enqueue_block_editor_assets</code> to a new <code>enqueue_block_assets</code> hook (<code>is_admin()</code> guarded) for WP 7.0&#39;s iframed editor; the editor JS stays put. Plus the full <code>package.json</code> + <code>composer.json</code> dependency bump set and changelog sync (2.0.7).</td></tr><tr><td><code>0.15.0</code></td><td>core 0.13 → 0.15</td><td>Vite 8 / Rolldown: <code>package.json</code> + <code>composer.json</code> dependency bumps, the <code>resources/scripts/app.ts</code> static-asset <code>import.meta.glob</code> fix, and changelog sync (2.1.0). The <code>vite.config.js</code> externals rewrite is a documented manual step (printed by the migration).</td></tr></tbody></table><h2 id="authoring-a-new-migration" tabindex="-1">Authoring a new migration <a class="header-anchor" href="#authoring-a-new-migration" aria-label="Permalink to &quot;Authoring a new migration&quot;">​</a></h2><p>Migrations live in <code>packages/webentor-codemods/migrations/</code> — each is a folder of ast-grep rule files and/or changelog blocks plus directory-based golden fixtures, registered in <code>migrations/index.json</code>. The runner and tests are generic, so adding one needs no code changes. See the package&#39;s <a href="https://github.com/Webikon/webentor-stack/tree/main/packages/webentor-codemods#how-its-built" target="_blank" rel="noreferrer">README</a> for the full layout, the id naming convention, and the step-by-step.</p>`,20)])])}const k=s(n,[["render",o]]);export{g as __pageData,k as default};
